import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import { connect } from 'react-redux';

import { Field, reduxForm } from 'redux-form';
import Grid from '@material-ui/core/Grid';
import FormControl from '@material-ui/core/FormControl';

import { renderTextField, renderCheckbox, radioButton, renderSelectField, renderDatePicker, renderCkEditor, renderImage } from '../_base/formComp';
import { validate } from './validate';

class FormOne extends PureComponent {
    constructor(props) {
        super(props);

        this.state = {
            selectedDate: new Date(),
        };

        this.handleSubmit = this.handleSubmit.bind(this);
        this.handleDateChange = this.handleDateChange.bind(this);
        this.handleEditorFocus = this.handleEditorFocus.bind(this);
        this.handleEditorBlur = this.handleEditorBlur.bind(this);
        this.handleEditorChange = this.handleEditorChange.bind(this);
        this.handleEditorOnInit = this.handleEditorOnInit.bind(this);
        this.handleImgUpload = this.handleImgUpload.bind(this);
    }

    handleSubmit = e => {
        e.preventDefault();
        console.log('handleSubmit');
    };

    handleEditorOnInit(data) {
        console.log('handleEditorOnInit: ', data);
    }

    handleDateChange(dateChange) {
        this.setState({
            selectedDate: dateChange,
        });
    }

    handleEditorFocus(data) {
        console.log('handleEditorFocus: ', data);
    }

    handleEditorBlur(data) {
        console.log('handleEditorBlur: ', data);
    }

    handleEditorChange(data) {
        console.log('handleEditorChange: ', data);
    }

    handleImgUpload(data) {
        console.log('handleImgUpload: ', data);
    }

    render() {
        const { selectedDate } = this.state;

        return (
            <section className="form-one">
                <form onSubmit={this.handleSubmit} className="frmComm">
                    <Grid item xs={6}>
                        <FormControl fullWidth>
                            <Field name="title" component={renderTextField} type="text" label="Title *" />
                        </FormControl>
                        <FormControl margin="normal" fullWidth>
                            <Field name="discount" component={renderTextField} type="number" label="Discount Percent *" />
                        </FormControl>
                        <FormControl margin="normal" fullWidth>
                            <Field name="position" component={renderTextField} type="number" label="Home Position" />
                        </FormControl>
                        <FormControl fullWidth>
                            <Field name="showHome" component={renderCheckbox} label="Show On Home" />
                        </FormControl>
                        <FormControl fullWidth>
                            <Field name="active" component={renderCheckbox} label="Active" />
                        </FormControl>
                        <FormControl className="flexDirRow" fullWidth>
                            <Field name="sex" component={radioButton} valueReceive="nam" label="Male" />
                            <Field name="sex" component={radioButton} valueReceive="nu" label="Female" />
                        </FormControl>
                        <FormControl margin="normal" fullWidth>
                            <Field name="favoriteColor" component={renderSelectField} label="Favorite Color" id="favColor">
                                <option value="" />
                                <option value="ff0000">Red</option>
                                <option value="00ff00">Green</option>
                                <option value="0000ff">Blue</option>
                            </Field>
                        </FormControl>
                        <FormControl margin="normal" fullWidth>
                            <Field
                                name="dateTimePicker"
                                component={renderDatePicker}
                                defaultValue={selectedDate}
                                handleDateChange={this.handleDateChange}
                                label="DateTimePicker"
                            />
                        </FormControl>
                        <FormControl margin="normal" fullWidth>
                            <Field
                                name="ckEditor"
                                label="Description"
                                component={renderCkEditor}
                                disabled={false}
                                defaultValue="<p>Hello</p> <p>Hello</p>"
                                handleEditorOnInit={this.handleEditorOnInit}
                                handleEditorFocus={this.handleEditorFocus}
                                handleEditorBlur={this.handleEditorBlur}
                                handleEditorChange={this.handleEditorChange}
                            />
                        </FormControl>
                        <FormControl margin="normal" fullWidth>
                            <Field
                                name="imgUpload"
                                label="Image *"
                                component={renderImage}
                                disabled={false}
                                defaultImg="https://storage.googleapis.com/vinid-public-staging/image/image_20190104_161916.jpeg"
                                handleImgUpload={this.handleImgUpload}
                            />
                        </FormControl>
                    </Grid>
                </form>
            </section>
        );
    }
}

FormOne.propTypes = {
    hasErr: PropTypes.bool.isRequired,
};

const mapStateToProps = state => {
    return {
        hasErr: false,
    };
};

export default reduxForm({
    form: 'frmOne',
    validate,
})(connect(mapStateToProps)(FormOne));
