import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import SwipeableViews from 'react-swipeable-views';
import Tabs from '@material-ui/core/Tabs';
import Tab from '@material-ui/core/Tab';
import Typography from '@material-ui/core/Typography';

import HeadTop from '../_base/headTop';
import FormOne from './form1';

const bredCrumArr = ['Form Demo'];
const titleShow = 'Form Demo';

const TabContainer = ({ children, dir }) => {
    return (
        <Typography component="div" dir={dir} style={{ padding: 24 }}>
            {children}
        </Typography>
    );
};

class FormDemo extends PureComponent {
    constructor(props) {
        super(props);

        this.state = {
            value: 0,
            axis: 'x', // x-reverse
        };

        this.handleChange = this.handleChange.bind(this);
        this.handleChangeIndex = this.handleChangeIndex.bind(this);
    }

    handleChange(event, newValue) {
        this.setState({
            value: newValue,
        });
    }

    handleChangeIndex(index) {
        this.setState({
            value: index,
        });
    }

    render() {
        const { value, axis } = this.state;

        return (
            <section className="formDemo">
                <HeadTop titleShow={titleShow} breadcrumbs={bredCrumArr} />
                <div className="mainContent">
                    <Tabs value={value} onChange={this.handleChange} indicatorColor="primary" textColor="primary" variant={null} className="tabComm">
                        <Tab label="Item One" />
                        <Tab label="Item Two" />
                        <Tab label="Item Three" />
                    </Tabs>

                    <SwipeableViews axis={axis} index={value} onChangeIndex={this.handleChangeIndex}>
                        <TabContainer dir={axis}>
                            <FormOne />
                        </TabContainer>
                        <TabContainer dir={axis}>Item Two</TabContainer>
                        <TabContainer dir={axis}>Item Three</TabContainer>
                    </SwipeableViews>
                </div>
            </section>
        );
    }
}

TabContainer.propTypes = {
    children: PropTypes.node.isRequired,
    dir: PropTypes.string.isRequired,
};

export default FormDemo;
